    for (i = 0; i < ZOPFLI_NUM_D; i++)
    {
        result->dists[i] =
            (size_t)(stats1->dists[i] * w1 + stats2->dists[i] * w2);
    }
    result->litlens[256] = 1; /* End symbol. */
}

